import { Platform } from 'react-native';

const generateToken = () => {
  return Platform.select({
    ios: () => Math.random().toString(36).substring(2, 15),
    android: () => Math.random().toString(36).substring(2, 20),
    default: () => Math.random().toString(36).substring(2, 10),
  });
};

export const useOfflineToken = () => {
  const [token, setToken] = useState(generateToken());

  useEffect(() => {
    const storeToken = async () => {
      try {
        await AsyncStorage.setItem('offlineToken', token);
      } catch (error) {
        console.error('Error storing offline token:', error);
      }
    };

    storeToken();
  }, []);

  return token;
};